    sl: { name: 'Ponči', meta_title: 'Surf ponči | surf-store.com', meta_description: 'Kupite surf ponče — za preoblačenje na plaži. Brezplačna dostava v EU nad 99€.' }
  },
}

applied = 0
TRANSLATIONS.each do |permalink, langs|
  taxon = Spree::Taxon.find_by(permalink: permalink)
  unless taxon
    puts "SKIP: #{permalink} not found"
    next
  end

  langs.each do |lang_code, fields|
    Mobility.with_locale(lang_code) do
      fields.each do |field, value|
        taxon.send("#{field}=", value)
      end
      taxon.save(validate: false)
    end
  end
  applied += 1
  print '.'
end

puts "\nApplied translations to #{applied} taxons in DE, ES, SL"
